diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 857efbdf687c..487c409c8b5c 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7425,12 +7425,66 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
 #endif

 VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
-  if (VPlans.empty())
+  if (CM.VF.isFixed()) {
+    if (isLegalForVF(CM.VF, CM.UF)) {
+      CM.BestVF = CM.VF;
+      return CM.VF;
+    }
+    return VectorizationFactor::Disabled();
+  }
+
+  SmallVector<VectorizationFactor, 8> VFs;
+  computeLegalVFs(VFs, *this);
+
+  if (VFs.empty())
+    return VectorizationFactor::Disabled();
+
+  VectorizationFactor BestFactor = VectorizationFactor::Disabled();
+  unsigned BestCost = -1U;
+
+  for (const auto &VF : VFs) {
+    unsigned NewCost = getVPCost(VF, CM.UF);
+    if (NewCost < BestCost) {
+      BestCost = NewCost;
+      BestFactor = VF;
+    }
+  }
+
+  if (BestFactor.isScalar())
     return VectorizationFactor::Disabled();
-  // If there is a single VPlan with a single VF, return it directly.
-  VPlan &FirstPlan = *VPlans[0];
-  if (VPlans.size() == 1 && size(FirstPlan.vectorFactors()) == 1)
-    return {*FirstPlan.vectorFactors().begin(), 0, 0};
+
+  CM.BestVF = BestFactor;
+
+#ifndef NDEBUG
+  auto getBestVFFromLegacy = [&]() {
+    InterleaveInfo.clear();
+    unsigned WidestInduction = Legal->getWidestInductionType()->getScalarSizeInBits();
+    for (const auto &VF : VFs) {
+      if (VF.Width > 1)
+        collectInstsToScalarize(VF.Width, WidestInduction);
+    }
+    return Cost->getBestVF(VFs, CM.UF);
+  };
+
+  VectorizationFactor LegacyVF = getBestVFFromLegacy();
+
+  if (LVP.InterleaveInfo.hasInterleavedAccesses())
+    return LegacyVF;
+
+  (void)LegacyVF;
+  VPlan &BestPlan = getPlanFor(BestFactor.Width);
+  VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(), CM);
+  precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
+  assert((BestFactor.Width == LegacyVF.Width ||
+          planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
+                                                CostCtx, OrigLoop)) &&
+         " VPlan cost model and legacy cost model disagreed");
+  assert((BestFactor.Width.isScalar() || BestFactor.ScalarCost > 0) &&
+         "when vectorizing, the scalar cost must be computed.");
+#endif
+
+  return BestFactor;
+}

   ElementCount ScalarVF = ElementCount::getFixed(1);
   assert(hasPlanWithVF(ScalarVF) &&
